module top_module(
  input clk,
  input reset,
  input enable,
  input [11:0] duration,
  output reg pulse
);reg [11:0] misleading_count;

  always @(posedge clk or posedge reset) begin
    if (reset) begin
      misleading_count <= 0;
      pulse <= 0;
    end else if (enable) begin
      if (misleading_count < duration) begin
        misleading_count <= misleading_count + 1;
        pulse <= 1;
      end else begin
        misleading_count <= 0;
        pulse <= 0;
      end
    end else begin
      misleading_count <= 0;
      pulse <= 0;
    end
  end

endmodule
